Greedy insertion with best-fit selection using route cost delta evaluation across all existing and potential empty assigns, falling back to forced creation if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    type cand struct {
        idx     int
        delta   float64
        success bool
    }
    for shipIDOffset, ori := range oris {
        des := dess[shipIDOffset]
        shipID := total_ship + shipIDOffset
        best := cand{idx: -1, delta: 1e18, success: false}
        for i := 0; i < dispatch.AssignsLen; i++ {
            oldCost := dispatch.Assigns[i].Cost
            ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
            if ok {
                dispatch.Assigns[i].GenRoute()
                newCost := dispatch.Assigns[i].Cost
                if newCost >= 0 {
                    delta := newCost - oldCost
                    if delta < best.delta {
                        best.idx = i
                        best.delta = delta
                        best.success = true
                    }
                }
            }
            dispatch.Assigns[i].RemoveShip(shipID)
            dispatch.Assigns[i].GenRoute()
        }
        if !best.success && dispatch.AssignsLen < MAXASSIGNS {
            best.idx = dispatch.AssignsLen
            best.success = true
        }
        if best.success {
            if best.idx == dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
            dispatch.Assigns[best.idx].AddShip(shipID, ori, des)
            dispatch.Assigns[best.idx].GenRoute()
        } else {
            for i := 0; i <= dispatch.AssignsLen; i++ {
                if i == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
                    dispatch.AssignsLen++
                }
                if i < MAXASSIGNS {
                    ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
                    if ok {
                        dispatch.Assigns[i].GenRoute()
                        if dispatch.Assigns[i].Cost >= 0 {
                            break
                        } else {
                            dispatch.Assigns[i].RemoveShip(shipID)
                            dispatch.Assigns[i].GenRoute()
                        }
                    }
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

